<template>
  <main>
    <a-radio-group v-model="statisticsType" @change="statisticsChange">
      <a-radio-button value="day"> 本日 </a-radio-button>
      <a-radio-button value="week"> 本周 </a-radio-button>
      <a-radio-button value="month"> 本月 </a-radio-button>
    </a-radio-group>
    <div style="font-size: 18px">
      今天一共花了<span style="font-size: 25px; color: #e84c3d"
        >{{ statisticsMoney }} </span
      >元
    </div>
    <span>
      <LL></LL>花了<span style="font-size: 25px; color: #e84c3d"
        >{{ llMoney }} </span
      >元</span
    >
    <a-divider type="vertical" />
    <span>
      <BB></BB>花了<span style="font-size: 25px; color: #e84c3d"
        >{{ bbMoney }} </span
      >元</span
    >
    <div style="margin-top:10px">
      节约大王是<span
        ><BB v-if="king === '颜臭屁'"></BB>
        <LL v-else-if="king === '林香香'"></LL>
        <span v-else>
          <LL></LL>和
          <BB></BB>
        </span>
      </span>
    </div>
    <a-divider type="horizontal" />
    <a-table
      size="small"
      :columns="columns"
      :loading="loading"
      @change="handleTableChange"
      :data-source="data"
      :pagination="pagination"
      :row-key="(record) => record.id"
      bordered
    >
      <span slot="operation" slot-scope="text, record" class="table-operation">
        <a-button type="danger" size="small" @click="remove(record)"
          ><a-icon type="delete"
        /></a-button>
      </span>
      <span slot="create" slot-scope="text">
        <BB v-if="text === '颜臭屁'"></BB>
        <LL v-else></LL>
      </span>
    </a-table>
  </main>
</template>
<script>
const columns = [
  {
    dataIndex: "create",
    key: "create",
    title: "谁",
    scopedSlots: { customRender: "create" },
  },
  {
    title: "花了",
    dataIndex: "money",
    key: "money",
  },
  {
    title: "在哪",
    dataIndex: "position",
    key: "position",
  },
  {
    title: "干啥",
    key: "tags",
    dataIndex: "tags",
  },
  {
    title: "为啥",
    key: "reason",
    dataIndex: "reason",
  },
  {
    title: "操作",
    key: "operation",
    scopedSlots: { customRender: "operation" },
  },
];
import moment from "moment";
import LL from "./LL";
import BB from "./BB";
export default {
  components: { LL, BB },
  data() {
    return {
      data: [],
      columns,
      limit: 10,
      loading: false,
      pagination: {},
      statisticsMoney: 0,
      llMoney: 0,
      bbMoney: 0,
      statisticsType: "day",
    };
  },
  computed: {
    king: function () {
      if (this.llMoney == this.bbMoney) {
        return "林香香和颜臭屁";
      } else if (this.llMoney < this.bbMoney) {
        return "林香香";
      } else {
        return "颜臭屁";
      }
    },
  },
  methods: {
    getTableData(page = 1) {
      this.loading = true;
      const query = new this.$Query("consume");
      query.limit(this.limit);
      query.skip(this.limit * (page - 1));
      query.find().then((result) => {
        this.data = result.map((i) => {
          i.attributes.id = i.id;
          return i.attributes;
        });
        this.loading = false;
      });
      const countQuery = new this.$Query("consume");
      countQuery.count().then((count) => {
        this.$set(this.pagination, "total", count);
      });
    },
    remove(record) {
      const consume = this.$AV.Object.createWithoutData("consume", record.id);
      consume.destroy();
      this.$message.success("删除成功");
      this.data = this.data.filter((i) => i.id != record.id);
    },
    handleTableChange(pagination) {
      const pager = { ...this.pagination };
      pager.current = pagination.current;
      this.pagination = pager;
      this.getTableData(pagination.current);
    },
    statisticsToday() {
      const query = new this.$AV.Query("consume");
      query.startsWith("time", moment().format("YYYY-MM-DD"));
      query.find().then((result) => {
        if (result.length === 0) {
          return;
        }
        this.statisticsMoney = result
          .map((i) => i.attributes.money)
          .reduce((a, b) => {
            return a + b;
          });
        this.llMoney = result
          .filter((i) => i.attributes.create == "林香香")
          .map((i) => i.attributes.money)
          .reduce((a, b) => {
            return a + b;
          });
        this.bbMoney = this.statisticsMoney - this.llMoney;
      });
    },
    statisticsWeek() {
      // 获取当前星期几
      let today = moment().weekday() + 1;
      const queryArr = [];
      while (today-- !== 0) {
        const query = new this.$AV.Query("consume");
        query.startsWith("time", moment().weekday(today).format("YYYY-MM-DD"));
        queryArr.push(query);
      }
      const query = new this.$AV.Query.or(...queryArr);
      query.find().then((result) => {
        if (result.length === 0) {
          return;
        }
        this.statisticsMoney = result
          .map((i) => i.attributes.money)
          .reduce((a, b) => {
            return a + b;
          });
        this.llMoney = result
          .filter((i) => i.attributes.create == "林香香")
          .map((i) => i.attributes.money)
          .reduce((a, b) => {
            return a + b;
          });
        this.bbMoney = this.statisticsMoney - this.llMoney;
      });
    },
    statisticsMonth() {
      const query = new this.$AV.Query("consume");
      query.startsWith("time", moment().format("YYYY-MM"));
      query.find().then((result) => {
        if (result.length === 0) {
          return;
        }
        this.statisticsMoney = result
          .map((i) => i.attributes.money)
          .reduce((a, b) => {
            return a + b;
          });
        this.llMoney = result
          .filter((i) => i.attributes.create == "林香香")
          .map((i) => i.attributes.money)
          .reduce((a, b) => {
            return a + b;
          });
        this.bbMoney = this.statisticsMoney - this.llMoney;
      });
    },
    statisticsChange() {
      this.statisticsMoney = 0;
      this.llMoney = 0;
      this.bbMoney = this.statisticsMoney - this.llMoney;
      if (this.statisticsType === "day") {
        this.statisticsToday();
      } else if (this.statisticsType === "week") {
        this.statisticsWeek();
      } else {
        this.statisticsMonth();
      }
    },
  },
  mounted() {
    this.getTableData();
    this.statisticsToday();
  },
};
</script>
