<template>
  <main>
    <a-form-model
      ref="ruleForm"
      :model="form"
      :rules="rules"
    >
      <a-form-model-item label="金额" prop="money">
        <a-input-number v-model="form.money" />
      </a-form-model-item>
      <a-form-model-item label="时间" required prop="time">
        <a-date-picker
          v-model="form.time"
          :locale="locale"
          show-time
          type="date"
          placeholder="何时花的"
          style="width: 100%"
        />
      </a-form-model-item>
      <a-form-model-item label="位置" prop="position">
        <a-input placeholder="在哪花的" v-model="form.position" />
      </a-form-model-item>
      <a-form-model-item label="标签" prop="tags">
        <a-select mode="multiple" v-model="form.tags" placeholder="标签" style="width: 200px">
          <a-select-option v-for="(tag, index) in tags" :value="tag" :key="index">
            {{ tag }}

          </a-select-option>
        </a-select>
      </a-form-model-item>
      <a-form-model-item label="原因" prop="reason">
        <a-input v-model="form.reason" type="textarea" />
      </a-form-model-item>
      <a-form-model-item :wrapper-col="{ offset: 1 }">
        <a-button-group>
          <a-button
            :loading="loading"
            type="primary"
            style="background:#16a184;border-color:#16a184"
            @click="onSubmit('颜臭屁')"
            ><a-icon type="man" />颜臭屁</a-button
          >
          <a-button
            :loading="loading"
            type="primary"
            style="background:#8e44ad;border-color:#8e44ad"
            @click="onSubmit('林香香')"
            ><a-icon type="woman" /> 林香香
          </a-button>
        </a-button-group>
      </a-form-model-item>
    </a-form-model>
    <a-modal
      :title="null"
      :closable="false"
      :visible="visible"
      @ok="handleOk"
      okText="行"
      cancelText=""
    >
      <p>记账成功<a-icon style="color: #52c41a" type="check-circle" /></p>
      <p>{{ form.create }}完成了一次记账，奖励一朵小红花🌹</p>
      <template slot="footer">
        <a-button @click="handleOk" type="primary">行</a-button>
      </template>
    </a-modal>
  </main>
</template>
<script>
import locale from "ant-design-vue/es/date-picker/locale/zh_CN";
import moment from "moment";
import "moment/locale/zh-cn";
export default {
  data() {
    return {
      other: "",
      locale,
      loading: false,
      form: {
        money: 0,
        time: moment(),
        create: "",
        position: "",
        reason: "",
        tags: [],
      },
      tags: [
        "游戏",
        "衣服",
        "淘宝",
        "美食",
        "医疗",
        "交通",
        "美妆",
        "通讯",
        "购物",
        "日用",
        "蔬菜",
        "水果",
        "零食",
        "运动",
        "娱乐",
        "美容",
        "住房",
        "居家",
        "长辈",
        "社交",
        "数码",
        "书籍",
        "学习",
        "礼金",
        "礼物",
        "办公",
        "维修",
        "捐赠",
        "亲友",
        "快递",
        "其他",
      ],
      rules: {
        money: [
          {
            required: true,
            type: "number",
            message: "一分没花？",
            trigger: "blur",
          },
        ],
        time: [{ required: true, message: "去年花的？", trigger: "change" }],
        position: [{ required: true, message: "在哪偷的？", trigger: "blur" }],
        tags: [
          {
            type: "array",
            message: "花哪儿了？",
            trigger: "change",
            range: [2, 10],
          },
        ],
      },
      visible: false,
    };
  },
  methods: {
    onSubmit(create) {
      this.form.create = create;
      this.$refs.ruleForm.validate((valid) => {
        if (valid) {
          this.save();
        } else {
          return false;
        }
      });
    },
    resetForm() {
      this.$refs.ruleForm.resetFields();
    },
    save() {
      this.loading = true;
      const consume = new this.$AV.Object("consume");
      consume.set("money", this.form.money);
      consume.set("time", this.form.time.format("YYYY-MM-DD HH:mm:ss"));
      consume.set("create", this.form.create);
      consume.set("position", this.form.position);
      consume.set("reason", this.form.reason);
      consume.set("tags", this.form.tags);
      consume.save().then(() => {
        this.visible = true;
        this.loading = false;
        setTimeout(() => {
          this.visible = false;
        }, 1000);
      });
    },
    handleOk() {
      this.visible = false;
    },
  },
  beforeCreate() {},
};
</script>
